    // Rate limiter вҖ” track berapa pesan dikirim per menit
    const _msgCounter = { count: 0, resetAt: Date.now() + 60000 }
    const _checkRateLimit = () => {
        const now = Date.now()
        if (now > _msgCounter.resetAt) {
            _msgCounter.count = 0
            _msgCounter.resetAt = now + 60000
        }
        _msgCounter.count++
        // Kalau lebih dari 25 pesan/menit, tambah delay extra
        return _msgCounter.count > 25
    }

