                    await sendWithTyping(from, { text: 'рҹҚі *RESEP ' + namaResep.toUpperCase() + '*\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n\n' + result }, { quoted: msg })
