                if ((lowerText === '.antijl on' || lowerText === '.antijl off')) { saveSecCfg(from, { antiJl: lowerText.includes('on')?'on':'off' }); return await sendWithTyping(from, { text: `рҹҡӘ *Anti Join-Leave: ${lowerText.includes('on')?'ON':'OFF'}*` }, { quoted: msg }) }
                if ((lowerText === '.antishorturl on' || lowerText === '.antishorturl off')) { saveSecCfg(from, { antiShortUrl: lowerText.includes('on')?'on':'off' }); return await sendWithTyping(from, { text: `рҹ”— *Anti Short URL: ${lowerText.includes('on')?'ON':'OFF'}*` }, { quoted: msg }) }
                if ((lowerText === '.captcha on' || lowerText === '.captcha off')) { saveSecCfg(from, { captcha: lowerText.includes('on')?'on':'off' }); return await sendWithTyping(from, { text: `рҹ”җ *Captcha: ${lowerText.includes('on')?'ON':'OFF'}*` }, { quoted: msg }) }
