                if ((lowerText === '.dsp on' || lowerText === '.dsp off')) { saveSecCfg(from, { deleteSticker: lowerText.includes('on')?'on':'off' }); return await sendWithTyping(from, { text: `рҹ“ӣ *Anti Stiker Spam: ${lowerText.includes('on')?'ON':'OFF'}*` }, { quoted: msg }) }

