                    await sendWithTyping(from, { video: ob, caption: `AUTO CAPTION PREMIUM\nWaktu: ${((Date.now()-_sPV8)/1000).toFixed(2)}s\nTimestamp + watermark ditambahkan`, mimetype: 'video/mp4' }, { quoted: msg })
